insert into bank_questions (question_key, subject_slug, page_id, page_name, source, qtype, marks, snapshot, answer_key)
values
('spanish:2-2-exercise-health-problems-and-advice:mcq:adf8943e', 'spanish', 'spanish:2-2-exercise-health-problems-and-advice', '2.2 Exercise, Health Problems and Advice', 'mcq', 'mcq', 1, '{"question": "What is the noun that goes with the verb ‘doler’ (to hurt)?", "options": ["el dolor", "el dolido", "el duelo", "el dolorido"]}'::jsonb, '{"answer": 0, "explain": "el dolor = pain. ‘el duelo’ (duel/mourning) and ‘dolorido’ (sore, an adjective) are real but different words — classic look-alike traps."}'::jsonb),
('spanish:2-2-exercise-health-problems-and-advice:mcq:7510ab26', 'spanish', 'spanish:2-2-exercise-health-problems-and-advice', '2.2 Exercise, Health Problems and Advice', 'mcq', 'mcq', 1, '{"question": "‘Mi abuelo se cayó’ means…", "options": ["My grandad fell over", "My grandad is going to fall over", "My grandad never falls over", "My grandad falls over often"]}'::jsonb, '{"answer": 0, "explain": "se cayó is the preterite (past) of caerse. The traps change it to future, or add ‘never’/‘often’ that was never said."}'::jsonb),
('spanish:2-2-exercise-health-problems-and-advice:mcq:f497828d', 'spanish', 'spanish:2-2-exercise-health-problems-and-advice', '2.2 Exercise, Health Problems and Advice', 'mcq', 'mcq', 1, '{"question": "Which is the best advice to relax?", "options": ["Hay que respirar profundamente", "Hay que respirar lo menos posible", "No se debe respirar durante el ejercicio", "Se debe dejar de respirar un momento"]}'::jsonb, '{"answer": 0, "explain": "Good advice: breathe deeply. The traps tell you to breathe as little as possible, not breathe while exercising, or stop breathing."}'::jsonb),
('spanish:2-2-exercise-health-problems-and-advice:tf:8ca2465b', 'spanish', 'spanish:2-2-exercise-health-problems-and-advice', '2.2 Exercise, Health Problems and Advice', 'tf', 'tf', 1, '{"question": "‘doler’ works like ‘gustar’ — it agrees with the body part, not the person."}'::jsonb, '{"answer": true, "explain": "Me duele la cabeza / me duelen los pies — the verb matches the body part."}'::jsonb),
('spanish:2-2-exercise-health-problems-and-advice:tf:178f0046', 'spanish', 'spanish:2-2-exercise-health-problems-and-advice', '2.2 Exercise, Health Problems and Advice', 'tf', 'tf', 1, '{"question": "‘Estoy constipado’ means ‘I am constipated’."}'::jsonb, '{"answer": false, "explain": "False friend! It means ‘I have a cold’."}'::jsonb),
('spanish:2-2-exercise-health-problems-and-advice:tf:eb9718c3', 'spanish', 'spanish:2-2-exercise-health-problems-and-advice', '2.2 Exercise, Health Problems and Advice', 'tf', 'tf', 1, '{"question": "‘se debe’ is followed by an infinitive."}'::jsonb, '{"answer": true, "explain": "se debe descansar / fumar / dormir — always an infinitive."}'::jsonb),
('spanish:2-2-exercise-health-problems-and-advice:tf:8e65815c', 'spanish', 'spanish:2-2-exercise-health-problems-and-advice', '2.2 Exercise, Health Problems and Advice', 'tf', 'tf', 1, '{"question": "‘dejar de fumar’ means ‘to start smoking’."}'::jsonb, '{"answer": false, "explain": "dejar de + infinitive = to STOP doing something — to stop smoking."}'::jsonb),
('spanish:2-2-exercise-health-problems-and-advice:tf:a64d29f0', 'spanish', 'spanish:2-2-exercise-health-problems-and-advice', '2.2 Exercise, Health Problems and Advice', 'tf', 'tf', 1, '{"question": "For temporary feelings like ‘tired’ you use ‘estar’ (estoy cansado)."}'::jsonb, '{"answer": true, "explain": "Temporary states use estar, not ser."}'::jsonb),
('spanish:2-2-exercise-health-problems-and-advice:tf:e5dd34ab', 'spanish', 'spanish:2-2-exercise-health-problems-and-advice', '2.2 Exercise, Health Problems and Advice', 'tf', 'tf', 1, '{"question": "‘la garganta’ means ‘the stomach’."}'::jsonb, '{"answer": false, "explain": "la garganta = throat; el estómago = stomach."}'::jsonb),
('spanish:2-2-exercise-health-problems-and-advice:tf:fefe9cfe', 'spanish', 'spanish:2-2-exercise-health-problems-and-advice', '2.2 Exercise, Health Problems and Advice', 'tf', 'tf', 1, '{"question": "‘acostarse’ is a reflexive verb, so ‘I go to bed’ is ‘me acuesto’."}'::jsonb, '{"answer": true, "explain": "Reflexive: me acuesto, te acuestas, se acuesta."}'::jsonb),
('spanish:2-2-exercise-health-problems-and-advice:tf:ad3d11ad', 'spanish', 'spanish:2-2-exercise-health-problems-and-advice', '2.2 Exercise, Health Problems and Advice', 'tf', 'tf', 1, '{"question": "‘Se debería evitar el estrés’ uses the conditional and suits Higher tier."}'::jsonb, '{"answer": true, "explain": "se debería = one should (conditional)."}'::jsonb),
('spanish:2-2-exercise-health-problems-and-advice:tf:783bbc79', 'spanish', 'spanish:2-2-exercise-health-problems-and-advice', '2.2 Exercise, Health Problems and Advice', 'tf', 'tf', 1, '{"question": "‘cuidar’ means ‘to take care of’."}'::jsonb, '{"answer": true, "explain": "cuidar = to look after / take care of."}'::jsonb),
('spanish:2-2-exercise-health-problems-and-advice:tf:06b42419', 'spanish', 'spanish:2-2-exercise-health-problems-and-advice', '2.2 Exercise, Health Problems and Advice', 'tf', 'tf', 1, '{"question": "‘la piel’ means ‘the leg’."}'::jsonb, '{"answer": false, "explain": "la piel = skin; la pierna = leg."}'::jsonb),
('spanish:2-2-exercise-health-problems-and-advice:tf:b562295c', 'spanish', 'spanish:2-2-exercise-health-problems-and-advice', '2.2 Exercise, Health Problems and Advice', 'tf', 'tf', 1, '{"question": "‘optimista’ describes someone with a negative attitude."}'::jsonb, '{"answer": false, "explain": "optimista = optimistic — a positive attitude."}'::jsonb),
('spanish:2-2-exercise-health-problems-and-advice:tf:80458c1b', 'spanish', 'spanish:2-2-exercise-health-problems-and-advice', '2.2 Exercise, Health Problems and Advice', 'tf', 'tf', 1, '{"question": "‘considerar hacer más ejercicio’ means to refuse to exercise."}'::jsonb, '{"answer": false, "explain": "considerar = to consider; it means considering doing more exercise, not refusing."}'::jsonb),
('spanish:2-2-exercise-health-problems-and-advice:tf:26482b56', 'spanish', 'spanish:2-2-exercise-health-problems-and-advice', '2.2 Exercise, Health Problems and Advice', 'tf', 'tf', 1, '{"question": "‘negarse a dejar de fumar’ means to refuse to stop smoking."}'::jsonb, '{"answer": true, "explain": "negarse a + infinitive = to refuse to do something."}'::jsonb),
('spanish:2-2-exercise-health-problems-and-advice:tf:aa2ebd8c', 'spanish', 'spanish:2-2-exercise-health-problems-and-advice', '2.2 Exercise, Health Problems and Advice', 'tf', 'tf', 1, '{"question": "‘acostumbrarse a hacer ejercicio’ means to get used to exercising."}'::jsonb, '{"answer": true, "explain": "acostumbrarse a = to get used to."}'::jsonb),
('spanish:2-2-exercise-health-problems-and-advice:tf:c6e8cd77', 'spanish', 'spanish:2-2-exercise-health-problems-and-advice', '2.2 Exercise, Health Problems and Advice', 'tf', 'tf', 1, '{"question": "‘Imagina un día sin estrés’ is an example of the past tense."}'::jsonb, '{"answer": false, "explain": "‘imagina’ here is a present/imperative form (imagine!), not a past tense."}'::jsonb),
('spanish:2-2-exercise-health-problems-and-advice:learn:6a64d7bc', 'spanish', 'spanish:2-2-exercise-health-problems-and-advice', '2.2 Exercise, Health Problems and Advice', 'learn', 'mcq', 1, '{"readingTitle": "How do I talk about exercise and sport?", "reading": "<p>The key verb is <span data-say=\"hacer ejercicio\">hacer ejercicio</span> (to do exercise / to work out). Here is the core vocabulary — tap 🔊 to hear each one.</p>\n            <table class=\"vocab-tbl\">\n              <tr><td><span data-say=\"el deporte\">el deporte</span></td><td>sport</td><td><span data-say=\"correr\">correr</span></td><td>to run</td></tr>\n              <tr><td><span data-say=\"nadar\">nadar</span></td><td>to swim</td><td><span data-say=\"montar en bicicleta\">montar en bicicleta</span></td><td>to cycle</td></tr>\n              <tr><td><span data-say=\"el gimnasio\">el gimnasio</span></td><td>the gym</td><td><span data-say=\"entrenar\">entrenar</span></td><td>to train</td></tr>\n              <tr><td><span data-say=\"estar en forma\">estar en forma</span></td><td>to be fit</td><td><span data-say=\"activo\">activo / activa</span></td><td>active</td></tr>\n            </table>\n            <p>Model sentence: <span data-say=\"Para estar en forma, hago ejercicio tres veces por semana.\">Para estar en forma, hago ejercicio tres veces por semana.</span> — <em>To be fit, I exercise three times a week.</em></p>\n            <table class=\"vocab-tbl\">\n              <tr><td><span data-say=\"fuerte\">fuerte</span></td><td>strong</td><td><span data-say=\"débil\">débil</span></td><td>weak</td></tr>\n            </table>\n            <p>Walking counts too: <span data-say=\"pasear\">pasear</span> (to walk / stroll) — <span data-say=\"Los fines de semana, paseo con mi perro para hacer ejercicio sin ir al gimnasio.\">Los fines de semana, paseo con mi perro para hacer ejercicio sin ir al gimnasio.</span> — <em>At weekends, I walk with my dog to exercise without going to the gym.</em> Some people check <span data-say=\"el reloj\">el reloj</span> (the clock/watch) to time their run — no importa si corres <span data-say=\"lento\">lento</span> (slowly) al principio.</p>\n            <p>It''s hard at first, but you <span data-say=\"te acostumbras a hacer ejercicio\">te acostumbras a hacer ejercicio</span> — <em>get used to exercising</em> — if you do it every week. <span data-say=\"Imagina un día sin estrés, lleno de deporte y aire libre.\">Imagina un día sin estrés, lleno de deporte y aire libre.</span> — <em>Imagine a day without stress, full of sport and fresh air.</em></p>", "question": "What does ‘estar en forma’ mean?", "options": ["to be fit", "to run a race", "to go to the gym building", "to fill in a paper form"]}'::jsonb, '{"answer": 0, "explain": "estar en forma = to be fit / in shape. It is a false friend — ‘forma’ here is not a paper ‘form’."}'::jsonb),
('spanish:2-2-exercise-health-problems-and-advice:learn:70ccf269', 'spanish', 'spanish:2-2-exercise-health-problems-and-advice', '2.2 Exercise, Health Problems and Advice', 'learn', 'mcq', 1, '{"readingTitle": "How do I say what hurts? (me duele / me duelen)", "reading": "<p>To say something hurts, use <strong>doler</strong> — and it behaves <em>exactly like</em> <strong>gustar</strong>: the verb agrees with the body part, not with you.</p>\n            <ul>\n              <li>ONE thing hurts → <span data-say=\"me duele\">me duele</span>: <span data-say=\"Me duele la cabeza.\">Me duele la cabeza.</span> (My head hurts.)</li>\n              <li>MORE THAN ONE → <span data-say=\"me duelen\">me duelen</span>: <span data-say=\"Me duelen los pies.\">Me duelen los pies.</span> (My feet hurt.)</li>\n            </ul>\n            <p>Body parts (<strong>el cuerpo</strong>):</p>\n            <table class=\"vocab-tbl\">\n              <tr><td><span data-say=\"la cabeza\">la cabeza</span></td><td>head</td><td><span data-say=\"el estómago\">el estómago</span></td><td>stomach</td></tr>\n              <tr><td><span data-say=\"la garganta\">la garganta</span></td><td>throat</td><td><span data-say=\"la espalda\">la espalda</span></td><td>back</td></tr>\n              <tr><td><span data-say=\"las piernas\">las piernas</span></td><td>legs</td><td><span data-say=\"los ojos\">los ojos</span></td><td>eyes</td></tr>\n              <tr><td><span data-say=\"la boca\">la boca</span></td><td>mouth</td><td><span data-say=\"el brazo\">el brazo</span></td><td>arm</td></tr>\n              <tr><td><span data-say=\"el corazón\">el corazón</span></td><td>heart</td><td><span data-say=\"la pierna\">la pierna</span></td><td>leg (singular)</td></tr>\n              <tr><td><span data-say=\"la piel\">la piel</span></td><td>skin</td><td><span data-say=\"el cerebro\">el cerebro</span></td><td>brain</td></tr>\n            </table>\n            <p><span data-say=\"el dolor\">el dolor</span> (pain) is the noun behind ‘doler’: <span data-say=\"Tengo un dolor de cabeza terrible.\">Tengo un dolor de cabeza terrible.</span> — <em>I have a terrible headache.</em></p>", "question": "Why is it ‘Me duelen los pies’ and not ‘Me duele los pies’?", "options": ["‘los pies’ is plural, so the verb is plural", "‘doler’ is a verb that is always plural in Spanish", "‘pies’ is a masculine noun", "it describes a future plan"]}'::jsonb, '{"answer": 0, "explain": "Like gustar, doler agrees with the body part; ‘los pies’ is plural → duelen (doler is NOT always plural)."}'::jsonb),
('spanish:2-2-exercise-health-problems-and-advice:learn:b37586a3', 'spanish', 'spanish:2-2-exercise-health-problems-and-advice', '2.2 Exercise, Health Problems and Advice', 'learn', 'mcq', 1, '{"readingTitle": "How do I describe health problems?", "reading": "<p>Use <strong>estar</strong> (a temporary state) for how you feel:</p>\n            <ul>\n              <li><span data-say=\"estar enfermo\">estar enfermo / enferma</span> — to be ill</li>\n              <li><span data-say=\"estar cansado\">estar cansado / cansada</span> — to be tired</li>\n              <li><span data-say=\"estar resfriado\">estar resfriado / resfriada</span> — to have a cold</li>\n              <li><span data-say=\"el estrés\">el estrés</span> — stress; <span data-say=\"estar estresado\">estar estresado</span> — to be stressed</li>\n            </ul>\n            <p>Example: <span data-say=\"Estoy muy cansado porque no duermo bien.\">Estoy muy cansado porque no duermo bien.</span> — <em>I am very tired because I don’t sleep well.</em></p>\n            <p><span data-say=\"una enfermedad\">una enfermedad</span> (an illness) can be <span data-say=\"serio\">serio / seria</span> (serious) — for example <span data-say=\"el cáncer\">el cáncer</span> (cancer), which is often linked to smoking <span data-say=\"un cigarrillo\">un cigarrillo</span> (a cigarette). Doctors also check <span data-say=\"la sangre\">la sangre</span> (blood): <span data-say=\"El médico me hizo un análisis de sangre porque estaba muy débil.\">El médico me hizo un análisis de sangre porque estaba muy débil.</span> — <em>The doctor did a blood test because I was very weak.</em></p>\n            <p>It''s important to <span data-say=\"saber reconocer los síntomas\">saber reconocer los síntomas</span> — <em>to know how to recognise the symptoms</em> — and to <span data-say=\"mencionar cualquier dolor al médico\">mencionar cualquier dolor al médico</span> — <em>to mention any pain to the doctor</em>.</p>", "question": "Which verb do you use for ‘I am tired’ — a temporary state?", "options": ["estar → estoy cansado", "ser → soy cansado", "tener → tengo cansado", "hacer → hago cansado"]}'::jsonb, '{"answer": 0, "explain": "Temporary states and feelings use estar: estoy cansado. ‘ser’ would describe a permanent trait."}'::jsonb),
('spanish:2-2-exercise-health-problems-and-advice:learn:de0ddfe8', 'spanish', 'spanish:2-2-exercise-health-problems-and-advice', '2.2 Exercise, Health Problems and Advice', 'learn', 'mcq', 1, '{"readingTitle": "How do I give health advice?", "reading": "<p>Reuse the advice structures from 2.1 — each is followed by an <strong>infinitive</strong>:</p>\n            <table class=\"vocab-tbl\">\n              <tr><td><span data-say=\"se debe descansar\">se debe descansar</span></td><td>one should rest</td></tr>\n              <tr><td><span data-say=\"no se debe fumar\">no se debe fumar</span></td><td>one must not smoke</td></tr>\n              <tr><td><span data-say=\"hay que dormir ocho horas\">hay que dormir ocho horas</span></td><td>you have to sleep eight hours</td></tr>\n              <tr><td><span data-say=\"deberías relajarte\">deberías relajarte</span> <span class=\"tier-h\">H</span></td><td>you should relax</td></tr>\n            </table>\n            <p>Example: <span data-say=\"Para evitar el estrés, se debe descansar y hacer ejercicio.\">Para evitar el estrés, se debe descansar y hacer ejercicio.</span></p>\n            <p>The verb <span data-say=\"cuidar\">cuidar</span> (to look after / take care of) is essential: <span data-say=\"Hay que cuidar tu salud y dormir suficiente.\">Hay que cuidar tu salud y dormir suficiente.</span> — <em>You have to look after your health and sleep enough.</em> A good night’s sleep is often the most <span data-say=\"efectivo\">efectivo</span> (effective) remedy, and it helps reduce <span data-say=\"el efecto\">el efecto</span> (the effect) of stress on the body.</p>\n            <p>A doctor might <span data-say=\"sugerir descansar más\">sugerir descansar más</span> — <em>suggest resting more</em> — and it''s a good idea to <span data-say=\"considerar hacer más ejercicio\">considerar hacer más ejercicio</span> — <em>consider doing more exercise</em>.</p>", "question": "What follows ‘se debe’, ‘hay que’ and ‘deberías’?", "options": ["an infinitive (descansar, dormir…)", "a verb conjugated in the preterite past tense", "an adjective that agrees", "a noun on its own"]}'::jsonb, '{"answer": 0, "explain": "All the advice structures take an infinitive."}'::jsonb),
('spanish:2-2-exercise-health-problems-and-advice:learn:148f189a', 'spanish', 'spanish:2-2-exercise-health-problems-and-advice', '2.2 Exercise, Health Problems and Advice', 'learn', 'mcq', 1, '{"readingTitle": "How do I talk about bad habits?", "reading": "<p>Common ‘malos hábitos’ (bad habits) and how to reject them:</p>\n            <ul>\n              <li><span data-say=\"fumar\">fumar</span> — to smoke; <span data-say=\"el tabaco\">el tabaco</span> — tobacco</li>\n              <li><span data-say=\"beber alcohol\">beber alcohol</span> — to drink alcohol; <span data-say=\"las drogas\">las drogas</span> — drugs</li>\n              <li><span data-say=\"dejar de fumar\">dejar de + infinitive</span> — to stop doing something: <span data-say=\"dejar de fumar\">dejar de fumar</span> (to stop smoking)</li>\n            </ul>\n            <p><span data-say=\"No se debe fumar porque es muy malo para la salud.\">No se debe fumar porque es muy malo para la salud.</span></p>\n            <p>Good habits matter too: <span data-say=\"lavarse los dientes\">lavarse los dientes</span> (to brush/wash your teeth) after meals, and <span data-say=\"la risa\">la risa</span> (laughter) — <span data-say=\"Dicen que la risa es la mejor medicina.\">Dicen que la risa es la mejor medicina.</span> — <em>They say laughter is the best medicine.</em> Taking care of your <span data-say=\"la imagen\">la imagen</span> (image) shouldn’t mean unhealthy habits, and the local health centre is normally <span data-say=\"abierto\">abierto</span> (open) every day if you need advice.</p>\n            <p>Some people <span data-say=\"se niegan a dejar de fumar\">se niegan a dejar de fumar</span> — <em>refuse to stop smoking</em> — even though they know it is bad for their health.</p>", "question": "‘dejar de fumar’ means…", "options": ["to stop smoking", "to let others smoke", "to smoke a little more", "to enjoy smoking outside"]}'::jsonb, '{"answer": 0, "explain": "dejar de + infinitive = to stop doing something; dejar de fumar = to stop smoking."}'::jsonb),
('spanish:2-2-exercise-health-problems-and-advice:learn:4e0e98dd', 'spanish', 'spanish:2-2-exercise-health-problems-and-advice', '2.2 Exercise, Health Problems and Advice', 'learn', 'mcq', 1, '{"readingTitle": "Higher: reflexives and future plans", "reading": "<p><span class=\"tier-h\">H</span> Many health verbs are <strong>reflexive</strong> — the action is done to yourself, so they take <strong>me / te / se</strong>:</p>\n            <ul>\n              <li><span data-say=\"relajarse\">relajarse</span> → <span data-say=\"me relajo\">me relajo</span> (I relax)</li>\n              <li><span data-say=\"acostarse\">acostarse</span> → <span data-say=\"me acuesto temprano\">me acuesto temprano</span> (I go to bed early)</li>\n            </ul>\n            <p>Combine with a plan or a conditional for the top band:</p>\n            <ul>\n              <li><span data-say=\"Voy a dejar de fumar y acostarme más temprano.\">Voy a dejar de fumar y acostarme más temprano.</span> <span class=\"tier-h\">H</span></li>\n              <li><span data-say=\"Se debería evitar el estrés para mantenerse sano.\">Se debería evitar el estrés para mantenerse sano.</span> <span class=\"tier-h\">H</span></li>\n            </ul>\n            <p><span class=\"tier-h\">H</span> Other useful reflexive/health verbs: <span data-say=\"caerse\">caerse</span> (to fall over) — <span data-say=\"Mi abuelo se cayó y le duele la pierna desde hace una semana.\">Mi abuelo se cayó y le duele la pierna desde hace una semana.</span> — <em>My grandad fell over and his leg has hurt for a week.</em> Don’t forget to <span data-say=\"respirar\">respirar</span> (breathe) deeply to relax. <span data-say=\"la salud mental\">la salud mental</span> (mental health) matters as much as physical health — being <span data-say=\"optimista\">optimista</span> (optimistic) helps, and a <span data-say=\"paciente\">paciente</span> (patient) who stays positive often recovers faster. <span class=\"tier-h\">H</span></p>", "question": "Which sentence correctly uses a reflexive verb?", "options": ["Me acuesto temprano", "Acuesto temprano cada noche", "Yo acuesto muy temprano", "Se acuesto temprano"]}'::jsonb, '{"answer": 0, "explain": "acostarse is reflexive: (yo) me acuesto. Dropping ‘me’ or using the wrong pronoun is wrong."}'::jsonb),
('spanish:2-2-exercise-health-problems-and-advice:misc:05500ed6', 'spanish', 'spanish:2-2-exercise-health-problems-and-advice', '2.2 Exercise, Health Problems and Advice', 'misc', 'mcq', 1, '{"readingTitle": "Misconception check", "reading": "<p><strong>❌ Common misconception:</strong> Me duele los pies.</p><p><strong>✅ The correct idea:</strong> Me duelen los pies.</p>", "question": "Why is ‘Me duele los pies’ wrong?", "options": ["‘los pies’ is plural, so it must be ‘duelen’", "you must always put the verb ‘estar’ in front of it", "‘pies’ needs a written accent", "the pronoun should be ‘te’, not ‘me’"]}'::jsonb, '{"answer": 0, "explain": "doler agrees with the body part; plural body part → duelen."}'::jsonb),
('spanish:2-2-exercise-health-problems-and-advice:misc:255a1152', 'spanish', 'spanish:2-2-exercise-health-problems-and-advice', '2.2 Exercise, Health Problems and Advice', 'misc', 'mcq', 1, '{"readingTitle": "Misconception check", "reading": "<p><strong>❌ Common misconception:</strong> Estoy constipado. (= I am constipated)</p><p><strong>✅ The correct idea:</strong> Estoy constipado. (= I have a cold)</p>", "question": "What does ‘constipado’ really mean?", "options": ["having a cold", "being constipated as you would guess", "feeling completely healthy", "being extremely tired"]}'::jsonb, '{"answer": 0, "explain": "Classic false friend: constipado = having a cold."}'::jsonb),
('spanish:2-2-exercise-health-problems-and-advice:misc:55a52a3c', 'spanish', 'spanish:2-2-exercise-health-problems-and-advice', '2.2 Exercise, Health Problems and Advice', 'misc', 'mcq', 1, '{"readingTitle": "Misconception check", "reading": "<p><strong>❌ Common misconception:</strong> Soy cansado.</p><p><strong>✅ The correct idea:</strong> Estoy cansado.</p>", "question": "Why ‘Estoy cansado’, not ‘Soy cansado’?", "options": ["tiredness is a temporary state → estar", "you should always use ‘tener’ with any feeling", "‘cansado’ is a plural adjective", "‘ser’ is only for the past"]}'::jsonb, '{"answer": 0, "explain": "Temporary states and moods take estar; ser would mean it is a permanent trait."}'::jsonb),
